function safeT(key, localeOverride) {
  const locale = localeOverride || currentLocale || DEFAULT_LOCALE;
  const table = (I18N && I18N[locale]) || {};
  const fallback = (I18N && I18N[DEFAULT_LOCALE]) || {};
  const template = table[key] || fallback[key];
  if (!template) return `TODO_i18n(${key})`;
  return interpolate(template, {});
}

function renderAboutSubSection() {
  const aboutContent = document.querySelector('.about-tab-content[data-tab="about"]');
  if (!aboutContent) return;

  const defaultKey = safeT("about.ui.defaultSectionKey", "en");
  if (ABOUT_VARIANTS.includes(defaultKey)) {
    aboutVariant = defaultKey;
  }

  const buildTabs = () =>
    ABOUT_VARIANTS.map((v) => {
      const active = v === aboutVariant;
      const label = safeT(`about.ui.tabs.${v}`);
      return `
        <button
          type="button"
          data-variant="${v}"
          style="
            padding: 8px 12px;
            border-radius: 999px;
            cursor: pointer;
            border: 1px solid rgba(255,255,255,0.14);
            background: ${active ? "rgba(255,255,255,0.14)" : "rgba(0,0,0,0.25)"};
            color: white;
            opacity: ${active ? "1" : "0.85"};
          "
        >${label}</button>
      `;
    }).join("");

  const titleKey = `about.sections.${aboutVariant}.title`;
  const bodyKey = `about.sections.${aboutVariant}.body`;

  const leftTitle = safeT(titleKey, "en");
  const leftBody = safeT(bodyKey, "en");
  const rightTitle = safeT(titleKey, currentLocale);
  const rightBody = safeT(bodyKey, currentLocale);

  aboutContent.innerHTML = `
    <div style="display:flex; flex-wrap:wrap; gap:8px; margin-bottom:12px;">${buildTabs()}</div>
    <div style="display:grid; grid-template-columns:1fr 1fr; gap:16px;">
      <div style="padding:12px; border-radius:12px; border:1px solid rgba(255,255,255,0.12);">
        <div style="opacity:0.7; font-size:12px; margin-bottom:8px;">English (en)</div>
        <h3 style="margin:0 0 8px 0;">${leftTitle}</h3>
        <p style="margin:0; line-height:1.6; opacity:0.92;">${leftBody}</p>
      </div>
      <div style="padding:12px; border-radius:12px; border:1px solid rgba(255,255,255,0.12);">
        <div style="opacity:0.7; font-size:12px; margin-bottom:8px;">${currentLocale} (i18n)</div>
        <h3 style="margin:0 0 8px 0;">${rightTitle}</h3>
        <p style="margin:0; line-height:1.6; opacity:0.92;">${rightBody}</p>
      </div>
    </div>
    <div style="display:flex; gap:10px; margin-top:12px; flex-wrap:wrap;">
      <button class="cta tiny">${safeT("about.ui.cta.primary")}</button>
      <button class="cta ghost tiny">${safeT("about.ui.cta.secondary")}</button>
    </div>
  `;

  aboutContent.querySelectorAll("button[data-variant]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const v = btn.dataset.variant;
      if (!v) return;
      aboutVariant = v;
      renderAboutSubSection();
    });
  });
}

function applyI18n() {
  document.querySelectorAll("[data-i18n]").forEach((el) => {
    const key = el.dataset.i18n;
    if (!key) return;
    const text = t(key, { spell: state.spell });
    if (text) {
      el.textContent = text;
    }
  });

  document.querySelectorAll("[data-i18n-placeholder]").forEach((el) => {
    const key = el.dataset.i18nPlaceholder;
    if (!key) return;
    const text = t(key);
    if (text) {
      el.setAttribute("placeholder", text);
    }
  });

  document.querySelectorAll("[data-i18n-aria]").forEach((el) => {
    const key = el.dataset.i18nAria;
    if (!key) return;
    const text = t(key);
    if (text) {
      el.setAttribute("aria-label", text);
    }
  });

  document.querySelectorAll("[data-i18n-html]").forEach((el) => {
    const key = el.dataset.i18nHtml;
    if (!key) return;
    const text = t(key, { spell: state.spell });
    if (text) {
      el.innerHTML = text;
    }
  });

  document.querySelectorAll(".dock-item").forEach((item) => {
    const labelEl = item.querySelector(".dock-label, .label, .dock-text");
    const label = labelEl ? labelEl.textContent.trim() : "";
    if (label) item.setAttribute("data-label", label);
    if (!item.hasAttribute("tabindex")) item.tabIndex = 0;
  });

  renderAboutSubSection();
}

function getPlatformLabel(platformId) {
  const locale = PLATFORM_LABELS[currentLocale] ? currentLocale : DEFAULT_LOCALE;
  return getPlatformLabelFromMap(locale, platformId);
}

function isSocialEnabled(platformId) {
  if (!SOCIAL_KEYS) return false;
  const direct = SOCIAL_KEYS[platformId];
  if (direct) return true;
  const upper = platformId.toUpperCase();
  if (SOCIAL_KEYS[upper]) return true;
  const snake = platformId.replace(/-/g, "_").toUpperCase();
  return Boolean(SOCIAL_KEYS[snake]);
}

function loginCopy(en, zh) {
  return currentLocale === "zh" ? zh : en;
}

function logoSlugFor(platformId) {
  const map = {
    apple: "apple",
    behance: "behance",
    discord: "discord",
    dribbble: "dribbble",
    facebook: "facebook",
    github: "github",
    gitlab: "gitlab",
    google: "google",
    instagram: "instagram",
    kakaotalk: "kakaotalk",
    line: "line",
    linkedin: "linkedin",
    medium: "medium",
    pinterest: "pinterest",
    reddit: "reddit",
    slack: "slack",
    stackoverflow: "stackoverflow",
    telegram: "telegram",
    tiktok: "tiktok",
    twitch: "twitch",
    wechat: "wechat",
    weibo: "sinaweibo",
    whatsapp: "whatsapp",
    x: "x"
  };
  return map[platformId] || platformId;
}

function logoColorFor(platformId) {
  const map = {
    apple: "ffffff",
    github: "ffffff",
    x: "ffffff",
    tiktok: "ffffff",
    google: "4285f4",
    facebook: "1877f2",
    wechat: "07c160"
  };
  return map[platformId] || "";
}

function providerLogoHtml(platformId, fallbackText) {
  if (platformId === "bsky") {
    return '<span class="login-logo-glyph bsky">🦋</span>';
  }
  if (platformId === "linkedin") {
    return '<span class="login-logo-glyph brand-text">in</span>';
  }
  if (platformId === "slack") {
    return '<span class="login-logo-glyph brand-text">sl</span>';
  }
  const slug = logoSlugFor(platformId);
  const color = logoColorFor(platformId);
  const src = `https://cdn.simpleicons.org/${slug}${color ? `/${color}` : ""}`;
  return `<img src="${src}" alt="${platformId}" class="login-logo" loading="lazy" referrerpolicy="no-referrer" /><span class="login-logo-fallback">${fallbackText}</span>`;
}

function providerLogoOnly(platformId) {
  if (!platformId) return '<span class="login-logo-glyph">?</span>';
  if (platformId === "bsky") return '<span class="login-logo-glyph bsky">🦋</span>';
  if (platformId === "linkedin") return '<span class="login-logo-glyph brand-text">in</span>';
  if (platformId === "slack") return '<span class="login-logo-glyph brand-text">sl</span>';
  const slug = logoSlugFor(platformId);
  const color = logoColorFor(platformId);
  const src = `https://cdn.simpleicons.org/${slug}${color ? `/${color}` : ""}`;
  return `<img src="${src}" alt="${platformId}" class="login-source-logo" loading="lazy" referrerpolicy="no-referrer" />`;
}

function renderLoginPlatforms() {
  if (!loginList) return;
  loginList.innerHTML = "";
  const enabledMap = new Map(
    authProviders.map((provider) => [
      provider.id,
      {
        enabled: provider.enabled,
        url: provider.url,
        icon: provider.icon,
        logo: provider.logo_url
      }
    ])
  );
  const linkedProviders = new Set(authState.linkedProviders || []);
  const list = socialPlatforms.map((platform) => {
    const record = enabledMap.get(platform.id);
    const logo = record?.logo;
    const isLinked = linkedProviders.has(platform.id);
    const iconHtml = logo
      ? `<img src="${logo}" alt="${platform.id}" class="login-logo" />`
      : providerLogoHtml(platform.id, record?.icon || platform.icon);
    const actionLabel = authState.user
      ? isLinked
        ? loginCopy("Linked", "已绑定")
        : loginCopy("Switch account", "切换账号")
      : record?.enabled
        ? loginCopy("Sign in", "登录")
        : loginCopy("Unavailable", "未开放");
    return {
      id: platform.id,
      icon: iconHtml,
      enabled: record?.enabled ?? isSocialEnabled(platform.id),
      url: record?.url || (record?.enabled ? `/auth/${platform.id}` : ""),
      linked: isLinked,
      actionLabel
    };
  });

  const summary = document.createElement("div");
  summary.className = "login-summary";
  if (authState.user) {
    const sourceProvider = authState.loginProvider || "";
    const sourceLabel = sourceProvider ? getPlatformLabel(sourceProvider) : loginCopy("Unknown", "未知");
    const linkedList = Array.from(linkedProviders).filter((providerId) => providerId !== "passkey");
    const linkedText = linkedList.length
      ? linkedList.map((providerId) => getPlatformLabel(providerId)).join(" · ")
      : loginCopy("No social provider linked yet", "还没有绑定社交账号");
    const label = authState.user.name || authState.user.email || authState.user.id || "";
    summary.innerHTML = `
      <div class="login-source-card">
        <div class="login-source-badge">${providerLogoOnly(sourceProvider)}</div>
        <div class="login-me-meta">
          <div class="login-me-title">${loginCopy("Current source platform", "当前来源平台")}</div>
          <div class="login-me-source-name">${sourceLabel}</div>
          <div class="login-me-user">${label}</div>
          <div class="login-me-linked">${loginCopy("Connected:", "已连接：")} ${linkedText}</div>
          <div class="login-switch-hint">${loginCopy("Tip: click an unlinked platform below to switch account.", "提示：点击下方未登录平台即可切换账号。")}</div>
        </div>
      </div>
    `;
  } else {
    const githubDiag = authState.authDiagnostics;
    const githubHint = githubDiag
      ? githubDiag.enabled
        ? t("login.githubDiagReady").replace(
            "{callback}",
            githubDiag.callback_url || "https://cssstudio.app/auth/github/callback"
          )
        : t("login.githubDiagMissing").replace(
            "{missing}",
            Array.isArray(githubDiag.missing_env) && githubDiag.missing_env.length
              ? githubDiag.missing_env.join(", ")
              : "unknown"
          )
      : "";
    summary.innerHTML = `
      <div class="login-hint">
        ${loginCopy("Choose a social account to continue. After sign-in, this panel will show your connected providers.", "选择一个社交账号登录。登录后，这里会显示你已绑定的平台和账号状态。")}
        ${githubHint ? `<div class="login-diagnostic-hint">${escapeHtml(githubHint)}</div>` : ""}
      </div>
    `;
  }
  loginList.appendChild(summary);

  const orderedList = authState.user
    ? [...list].sort((a, b) => Number(a.linked) - Number(b.linked))
    : list;

  orderedList.forEach((platform) => {
    const enabled = Boolean(platform.enabled);
    const card = document.createElement(enabled && !platform.linked ? "a" : "div");
    const stateClass = platform.linked ? "linked" : enabled ? "enabled" : "disabled";
    card.className = `login-card ${stateClass}`;
    if (enabled && platform.url) {
      card.href = platform.url;
    }
    card.innerHTML = `
      <div class="login-icon">${platform.icon}</div>
      <div class="login-title-wrap">
        <div class="login-title">${getPlatformLabel(platform.id)}</div>
        <div class="login-action-tag">${platform.actionLabel}</div>
      </div>
      ${platform.linked && authState.user ? `<button class="cta ghost tiny login-unlink-btn" type="button" data-provider="${platform.id}">${loginCopy("Unlink", "解绑")}</button>` : ""}
    `;
    loginList.appendChild(card);
  });

  // Bluesky login (handle + app password) if enabled
  const bsky = enabledMap.get("bsky");
  if (bsky && bsky.enabled) {
    const form = document.createElement("div");
    form.className = "login-bluesky";
    form.innerHTML = `
      <div class="login-title">Bluesky</div>
      <div class="login-row">
        <input type="text" id="bsky-handle" placeholder="handle (e.g. name.bsky.social)" />
      </div>
      <div class="login-row">
        <input type="password" id="bsky-app-password" placeholder="app password" />
      </div>
      <button class="cta tiny" id="bsky-login-btn" type="button">Login</button>
    `;
    loginList.appendChild(form);

    const btn = form.querySelector("#bsky-login-btn");
    btn?.addEventListener("click", async () => {
      const handle = form.querySelector("#bsky-handle")?.value?.trim();
      const appPassword = form.querySelector("#bsky-app-password")?.value?.trim();
      if (!handle || !appPassword) {
        showToast(t("login.statusGuest"));
        return;
      }
      try {
        const res = await fetch("/auth/bluesky", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({ handle, app_password: appPassword })
        });
        if (res.ok) {
          await fetchMe();
        }
      } catch (err) {
        // ignore
      }
    });
  }
}

function normalizeVersionList(payload) {
  if (!payload) return [];
  if (Array.isArray(payload)) {
    return payload.map((item) => (typeof item === "string" ? { id: item } : item));
  }
  if (Array.isArray(payload.versions)) {
    return payload.versions.map((item) => (typeof item === "string" ? { id: item } : item));
  }
  return [];
}

async function loadVersions() {
  if (!versionToggle || !versionMenu || !versionList) return;
  try {
    const [currentRes, listRes] = await Promise.all([
      fetch("/version.json", { cache: "no-store" }).catch(() => null),
      fetch("/versions.json", { cache: "no-store" }).catch(() => null)
    ]);
    const currentData = currentRes && currentRes.ok ? await currentRes.json() : null;
    const listData = listRes && listRes.ok ? await listRes.json() : null;
    const current =
      currentData?.version || currentData?.id || listData?.current || "current";
    const versions = normalizeVersionList(listData);
    if (!versions.length) {
      versionToggle.classList.add("is-hidden");
      return;
    }
    if (versionCurrentLabel) {
      versionCurrentLabel.textContent = `${t("versions.current")} · ${current}`;
    }
    versionList.innerHTML = "";
    versions.forEach((entry) => {
      const id = entry.id || entry.version || entry.name;
      if (!id) return;
      const safePath = `/v/${encodeURIComponent(id)}/`;
      const label = entry.label || id;
      const item = document.createElement("a");
      item.href = safePath;
      item.className = `version-item ${id === current ? "active" : ""}`;
      item.innerHTML = `
        <span>${label}</span>
        <span>${entry.createdAt || entry.date || ""}</span>
      `;
      item.addEventListener("click", (event) => {
        event.preventDefault();
        window.location.assign(safePath);
      });
      versionList.appendChild(item);
    });
  } catch (err) {
    versionToggle.classList.add("is-hidden");
  }
}

function initVersionSwitcher() {
  if (!versionToggle || !versionMenu) return;
  versionToggle.addEventListener("click", (event) => {
    event.stopPropagation();
    versionMenu.classList.toggle("is-hidden");
  });
  document.addEventListener("click", () => {
    versionMenu.classList.add("is-hidden");
  });
  loadVersions();
}

function initAboutTabs() {
  if (!aboutTabs.length || !aboutTabContents.length) return;
  aboutTabs.forEach((tab) => {
    tab.addEventListener("click", () => {
      const key = tab.dataset.tab;
      if (!key) return;
      aboutTabs.forEach((btn) => btn.classList.remove("active"));
      aboutTabContents.forEach((panel) => panel.classList.remove("active"));
      tab.classList.add("active");
      const content = document.querySelector(`.about-tab-content[data-tab="${key}"]`);
      if (content) content.classList.add("active");
      if (key === "about") {
        renderAboutSubSection();
      }
    });
  });
  renderAboutSubSection();
}

function initApiBillingUI() {
  renderApiBillingPanel();
}

function setSelectValueSafe(selectEl, value) {
  if (!selectEl || !value) return;
  const opts = Array.from(selectEl.options || []);
  const found = opts.find((o) => o.value === value || o.text === value);
  if (found) {
    selectEl.value = found.value;
    return;
  }
  const opt = document.createElement("option");
  opt.value = value;
  opt.textContent = value;
  selectEl.appendChild(opt);
  selectEl.value = value;
}

function hashSeedString(input) {
  const text = String(input || "");
  let hash = 2166136261;
  for (let i = 0; i < text.length; i += 1) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

function seededUnit(seed, offset = 0) {
  const value = Math.sin((seed + 1 + offset) * 12.9898) * 43758.5453;
  return value - Math.floor(value);
}

function seededPick(list, seed, offset = 0) {
  const items = Array.isArray(list) ? list : [];
  if (!items.length) return "";
  const index = Math.floor(seededUnit(seed, offset) * items.length) % items.length;
  return items[index];
}

function seededNumber(min, max, step, seed, offset = 0) {
  const safeMin = Number(min || 0);
  const safeMax = Number(max || safeMin);
  const safeStep = Math.max(1, Number(step || 1));
  const count = Math.max(1, Math.floor((safeMax - safeMin) / safeStep) + 1);
  return safeMin + (Math.floor(seededUnit(seed, offset) * count) % count) * safeStep;
}

function syncCreationStateToLegacyInputs() {
  const genre = creationState.selections.genre || "Chinese GuFeng";
  const mood = creationState.selections.mood;
  const instrument = creationState.selections.instrument;
  const instrumentation = creationState.instrumentation || "";
  const ensembleStyle = creationState.ensembleStyle || "";
  const styleText = [genre, mood, instrument, instrumentation, ensembleStyle].filter(Boolean).join(" · ");
  setSelectValueSafe(styleInput, styleText || genre);
  setSelectValueSafe(voiceInput, creationState.selections.vocalGender || "Feminine");
}

function normalizeWorkTypeClient(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (raw === "triptych") return "triptych";
  if (raw === "opera") return "opera";
  return "single";
}

function inferStructuredWorkType(title, fallback = "single") {
  const text = String(title || "").trim();
  if (text.includes("三部曲")) return "triptych";
  if (text.includes("歌剧")) return "opera";
  return normalizeWorkTypeClient(fallback);
}

function workTypeLabel(workType) {
  const normalized = normalizeWorkTypeClient(workType);
  if (normalized === "triptych") return loginCopy("Triptych", "三部曲");
  if (normalized === "opera") return loginCopy("Opera", "歌剧");
  return loginCopy("Single", "单曲");
}

function workStructureRoleLabel(role, fallbackType) {
  const raw = String(role || "").trim().toLowerCase();
  if (raw === "act") return loginCopy("Act", "幕");
  if (raw === "scene") return loginCopy("Scene", "场");
  if (raw === "triptych") return loginCopy("Triptych", "三部曲");
  if (raw === "opera") return loginCopy("Opera", "歌剧");
  return workTypeLabel(fallbackType);
}

function workOwnerChainLabel(chain) {
  const items = Array.isArray(chain) ? chain : [];
  const labels = items
    .map((entry) => String(entry?.label || "").trim())
    .filter(Boolean);
  if (!labels.length) return "";
  return `${loginCopy("Ownership", "流转")} · ${labels.join(" → ")}`;
}

function flattenHierarchyWorks(items) {
  const list = Array.isArray(items) ? items : [];
  const flat = [];
  const walk = (node) => {
    if (!node || typeof node !== "object") return;
    flat.push(node);
    const children = Array.isArray(node.children) ? node.children : [];
    children.forEach(walk);
  };
  list.forEach(walk);
  return flat;
}

function renderHierarchyTree(nodes, context = "market") {
  const items = Array.isArray(nodes) ? nodes : [];
  if (!items.length) return "";
  return `
    <div class="work-hierarchy">
      ${items
        .map((node, index) => {
          const title = escapeHtml(String(node?.title || "").trim() || loginCopy("Untitled", "未命名"));
          const role = escapeHtml(workStructureRoleLabel(node?.structure_role, node?.work_type));
          const summary = escapeHtml(String(node?.style || node?.lyrics_preview || "").trim());
          const createdAt = formatDateTime(node?.created_at);
          const children = renderHierarchyTree(node?.children || [], context);
          const workId = escapeHtml(String(node?.id || "").trim());
          const listenCents = Number(node?.current_listen_price_cents || 0);
          const buyoutCents = Number(node?.current_buyout_price_cents || 0);
          const buyoutEnabled = Boolean(node?.buyout_enabled) && buyoutCents > 0;
          const actions =
            context === "market" && workId
              ? `
                <div class="work-hierarchy-actions">
                  <button class="mini-btn ghost tiny" type="button" data-market-action="preview" data-market-child-id="${workId}">${loginCopy("Preview", "预览")}</button>
                  <button class="mini-btn ghost tiny" type="button" data-market-action="listen" data-market-child-id="${workId}" ${listenCents > 0 ? "" : "disabled"}>${loginCopy("Listen", "聆听")}</button>
                  <button class="mini-btn market-buyout-btn tiny" type="button" data-market-action="buyout" data-market-child-id="${workId}" ${buyoutEnabled ? "" : "disabled"}>${loginCopy("Buyout", "买断")}</button>
                </div>
              `
              : context === "works" && workId
              ? `
                <div class="work-hierarchy-actions">
                  <button class="mini-btn ghost tiny" type="button" data-work-action="watch" data-work-child-id="${workId}">${loginCopy("Enjoy", "欣赏")}</button>
                </div>
              `
              : "";
          return `
            <details class="work-hierarchy-item" ${index === 0 ? "open" : ""}>
              <summary>
                <span class="work-hierarchy-role">${role}</span>
                <span class="work-hierarchy-title">${title}</span>
                ${createdAt ? `<span class="work-hierarchy-time">${escapeHtml(createdAt)}</span>` : ""}
              </summary>
              ${summary ? `<div class="work-hierarchy-summary">${summary}</div>` : ""}
              ${actions}
              ${children}
            </details>
          `;
        })
        .join("")}
    </div>
  `;
}

function workTypePricingDefaults(workType) {
  const stored = panelDefaultsState.creation?.pricing_by_type?.[normalizeWorkTypeClient(workType)] || null;
  if (stored) {
    return {
      listenCents: Number(stored.listen_cents || 99),
      buyoutCents: Number(stored.buyout_cents || 299)
    };
  }
  const normalized = normalizeWorkTypeClient(workType);
  if (normalized === "triptych") return { listenCents: 99, buyoutCents: 499 };
  if (normalized === "opera") return { listenCents: 99, buyoutCents: 999 };
  return { listenCents: 99, buyoutCents: 299 };
}

function buildCurrentCreationDefaultsPayload() {
  const workType = normalizeWorkTypeClient(creationState.workType);
  const pricingByType = panelDefaultsState.creation?.pricing_by_type
    ? JSON.parse(JSON.stringify(panelDefaultsState.creation.pricing_by_type))
    : {
        single: { listen_cents: 99, buyout_cents: 299 },
        triptych: { listen_cents: 99, buyout_cents: 499 },
        opera: { listen_cents: 99, buyout_cents: 999 }
      };
  const listenCents = centsFromPriceInput(creationDefaultListen?.value || "");
  const buyoutCents = centsFromPriceInput(creationDefaultBuyout?.value || "");
  pricingByType[workType] = {
    listen_cents: listenCents > 0 ? listenCents : workTypePricingDefaults(workType).listenCents,
    buyout_cents: buyoutCents >= 0 ? buyoutCents : workTypePricingDefaults(workType).buyoutCents
  };
  return {
    creative: {
      genre: creationState.selections.genre || "",
      mood: creationState.selections.mood || "",
      instrument: creationState.selections.instrument || "",
      instrumentation: creationState.instrumentation || "",
      ambience: creationState.selections.ambience || "",
      vocal_gender: creationState.selections.vocalGender || "",
      vocal_style: creationState.vocalStyle || "",
      ensemble_style: creationState.ensembleStyle || "",
      arrangement_density: Number(creationState.arrangementDensity || 0.6),
      dynamics_curve: creationState.dynamicsCurve || "",
      section_form: creationState.sectionForm || "",
      articulation_bias: creationState.articulationBias || "",
      voicing_register: creationState.voicingRegister || "",
      percussion_activity: Number(creationState.percussionActivity || 0.45),
      expression_cc_bias: creationState.expressionCcBias || "",
      humanization: Number(creationState.humanization || 0.35),
      inspiration_notes: String(creationState.inspirationNotes || "").slice(0, 1000),
      licensed_style_pack: creationState.licensedStylePack || "",
      external_audio_adapter: creationState.externalAudioAdapter || "",
      tempo_bpm: Number(creationState.tempo || 88),
      musical_key: creationState.key || "C",
      duration_s: Number(creationState.duration || 180),
      language: creationState.language || "zh",
      prompt: String(creationState.prompt || "").slice(0, 500),
      work_type: workType
    },
    pricing_by_type: pricingByType
  };
}

function applyCreationDefaults(template) {
  if (!template || typeof template !== "object") return;
  panelDefaultsState.creation = template;
  const creative = template.creative || {};
  creationState.selections = {
    genre: String(creative.genre || "Chinese GuFeng"),
    mood: String(creative.mood || ""),
    instrument: String(creative.instrument || ""),
    ambience: String(creative.ambience || ""),
    vocalGender: String(creative.vocal_gender || "Feminine")
  };
  creationState.instrumentation = String(creative.instrumentation || "");
  creationState.vocalStyle = String(creative.vocal_style || "");
  creationState.ensembleStyle = String(creative.ensemble_style || "");
  creationState.arrangementDensity = Math.max(0.2, Math.min(1, Number(creative.arrangement_density || 0.6)));
  creationState.dynamicsCurve = String(creative.dynamics_curve || "");
  creationState.sectionForm = String(creative.section_form || "");
  creationState.articulationBias = String(creative.articulation_bias || "");
  creationState.voicingRegister = String(creative.voicing_register || "");
  creationState.percussionActivity = Math.max(0, Math.min(1, Number(creative.percussion_activity || 0.45)));
  creationState.expressionCcBias = String(creative.expression_cc_bias || "");
  creationState.humanization = Math.max(0, Math.min(1, Number(creative.humanization || 0.35)));
  creationState.inspirationNotes = String(creative.inspiration_notes || "").slice(0, 1000);
  creationState.licensedStylePack = String(creative.licensed_style_pack || "");
  creationState.externalAudioAdapter = String(creative.external_audio_adapter || "");
  creationState.tempo = Number(creative.tempo_bpm || 88);
  creationState.key = String(creative.musical_key || "C");
  creationState.duration = Number(creative.duration_s || 180);
  creationState.language = String(creative.language || "zh");
  creationState.workType = normalizeWorkTypeClient(creative.work_type || "single");
  creationState.prompt = String(creative.prompt || "").slice(0, 500);
  syncCreationStateToLegacyInputs();
  const pricing = workTypePricingDefaults(creationState.workType);
  if (creationDefaultListen) creationDefaultListen.value = (pricing.listenCents / 100).toFixed(2);
  if (creationDefaultBuyout) creationDefaultBuyout.value = (pricing.buyoutCents / 100).toFixed(2);
  renderCreationConsole();
}

async function loadCreationPanelDefaults(force = false) {
  if (panelDefaultsState.loading) return panelDefaultsState.creation;
  if (!force && panelDefaultsState.loaded && panelDefaultsState.creation) return panelDefaultsState.creation;
  panelDefaultsState.loading = true;
  try {
    const res = await fetch("/api/panel-defaults/creation", { credentials: "include" });
    const payload = await res.json().catch(() => null);
    const data = getApiData(payload);
    const defaults = data?.defaults || null;
    if (res.ok && defaults) {
      panelDefaultsState.loaded = true;
      applyCreationDefaults(defaults);
      return defaults;
    }
  } catch (_err) {
    // ignore
  } finally {
    panelDefaultsState.loading = false;
  }
  return panelDefaultsState.creation;
}

async function saveCreationPanelDefaults(trigger) {
  if (getUserRole() !== "admin") return;
  try {
    setButtonBusy(trigger, true);
    const res = await fetch("/api/panel-defaults/creation", {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ defaults: buildCurrentCreationDefaultsPayload() })
    });
    const payload = await res.json().catch(() => null);
    const data = getApiData(payload);
    if (!res.ok || payload?.ok === false || !data?.defaults) {
      throw new Error(payload?.code || `defaults_save_failed:${res.status}`);
    }
    applyCreationDefaults(data.defaults);
    showToast(loginCopy("Default template saved.", "默认模板已保存。"));
  } catch (_err) {
    showToast(loginCopy("Failed to save defaults.", "保存默认模板失败。"));
  } finally {
    setButtonBusy(trigger, false);
  }
}

function creationSummaryText() {
  const s = creationState.selections;
  const styleSummary = String(styleInput?.value || "").trim();
  const parts = [
    styleSummary && `${t("settings.musicStyle")}: ${styleSummary}`,
    s.genre && `${creationTabLabel("genre")}: ${creationChipLabel("genre", s.genre)}`,
    s.mood && `${creationTabLabel("mood")}: ${creationChipLabel("mood", s.mood)}`,
    s.instrument && `${creationTabLabel("instrument")}: ${creationChipLabel("instrument", s.instrument)}`,
    s.ambience && `${creationTabLabel("ambience")}: ${creationChipLabel("ambience", s.ambience)}`,
    s.vocalGender && `${creationTabLabel("vocalGender")}: ${creationChipLabel("vocalGender", s.vocalGender)}`,
    creationState.instrumentation && `${loginCopy("Instrumentation", "编制")}: ${creationState.instrumentation}`,
    creationState.vocalStyle && `${loginCopy("Vocal Style", "唱腔")}: ${creationState.vocalStyle}`,
    creationState.ensembleStyle && `${loginCopy("Ensemble", "编制风格")}: ${creationState.ensembleStyle}`,
    creationState.licensedStylePack && `${loginCopy("Licensed Pack", "授权风格包")}: ${creationState.licensedStylePack}`,
    creationState.externalAudioAdapter && `${loginCopy("Audio Adapter", "外部音频适配器")}: ${creationState.externalAudioAdapter}`,
    creationState.voicingRegister && `${loginCopy("Register", "音区")}: ${creationState.voicingRegister}`,
    creationState.expressionCcBias && `${loginCopy("Expression", "表情控制")}: ${creationState.expressionCcBias}`,
    `${loginCopy("Percussion", "打击活跃度")}: ${Math.round(Number(creationState.percussionActivity || 0) * 100)}%`,
    `${loginCopy("Humanization", "拟真演奏")}: ${Math.round(Number(creationState.humanization || 0) * 100)}%`,
    `${loginCopy("Work Type", "作品类型")}: ${workTypeLabel(creationState.workType)}`,
    `${t("settings.tempoBpm")}: ${creationState.tempo} BPM`,
    `${t("settings.key")}: ${creationState.key}`,
    `${t("settings.durationSec")}: ${creationState.duration}s`,
    `${t("settings.language")}: ${creationState.language}`
  ].filter(Boolean);
  return parts.join(" | ");
}

