function randomizeCreationForLyricsRefresh(title) {
  const seed = hashSeedString(`${title}::${Date.now()}::${songSeedVariationCounter}`);
  creationState.selections = {
    genre: seededPick(creationOptionCatalog.genre, seed, 1) || "Chinese GuFeng",
    mood: seededPick(creationOptionCatalog.mood, seed, 2) || "",
    instrument: seededPick(creationOptionCatalog.instrument, seed, 3) || "",
    ambience: seededPick(creationOptionCatalog.ambience, seed, 4) || "",
    vocalGender: seededPick(creationOptionCatalog.vocalGender, seed, 5) || "Feminine"
  };
  creationState.tempo = seededNumber(68, 168, 4, seed, 6);
  creationState.key = seededPick(["C", "D", "E", "F", "G", "A", "B"], seed, 7) || "C";
  creationState.duration = seededPick([30, 45, 60, 75, 90, 120], seed, 8) || 60;
  creationState.language = seededPick(["zh", "en", "ja"], seed, 9) || "zh";
  creationState.workType = seededPick(["single", "triptych", "opera"], seed, 10) || "single";
  creationState.prompt = loginCopy(
    `Randomized from title: ${title}`,
    `由标题随机生成：${title}`
  );
  creationState.instrumentation = seededPick(
    [
      "guzheng, dizi, low strings",
      "grand piano, cello, brushed drums",
      "analog bass, polysynth pad, punchy kit",
      "chamber strings, horn layer, taiko pulse"
    ],
    seed,
    11
  ) || "";
  creationState.vocalStyle = seededPick(
    ["airy close-mic", "lyric belt", "soft opera shimmer", "soul rasp", "choral unison"],
    seed,
    12
  ) || "";
  creationState.ensembleStyle = seededPick(
    ["chamber ensemble", "festival percussion circle", "synth-pop band", "cinematic orchestra"],
    seed,
    13
  ) || "";
  creationState.licensedStylePack = "";
  creationState.externalAudioAdapter = "";
  creationState.inspirationNotes = loginCopy(
    "Use broad lawful references: era, region, instrumentation, emotional pacing, and any licensed pack names.",
    "使用合法的宽参考：时代、地域、编制、情绪推进，以及已授权音源包名称。"
  );
  syncCreationStateToLegacyInputs();
  randomizePalette();
  renderCreationConsole();
}

function formatCreationLanguageBadge(lang) {
  const value = String(lang || "").trim().toLowerCase();
  if (value === "ja") return "JP";
  if (value === "en") return "EN";
  if (value === "zh") return loginCopy("CN", "中文");
  return value.toUpperCase() || "--";
}

function describeCreationRandomization() {
  return [
    formatCreationLanguageBadge(creationState.language),
    `${creationState.tempo} BPM`,
    `${creationState.key} major`,
    `${creationState.duration}s`
  ].join(" · ");
}

function openCreationConsole() {
  openPanel(settingsPanel);
  creationState.activeTab = "genre";
  renderCreationConsole();
  const box = document.getElementById("creation-console");
  box?.scrollIntoView({ behavior: "smooth", block: "center" });
}

function setButtonBusy(button, busy) {
  if (!(button instanceof HTMLButtonElement)) return;
  button.disabled = !!busy;
  button.classList.toggle("is-busy", !!busy);
}

async function regenerateSeedFields(target) {
  const triggerMap = {
    lyrics: lyricsRegenerate,
    style: styleRegenerate,
    structure: musicStructureRegenerate,
    outline: videoOutlineRegenerate,
    scenes: sectionPromptsRegenerate
  };
  const trigger = triggerMap[target] || lyricsRegenerate;
  const title = titleInput?.value?.trim() || "";
  if (!title) {
    showToast(t("toast.seedRefreshNeedsTitle"));
    titleInput?.focus?.();
    return;
  }
  try {
    setButtonBusy(trigger, true);
    if (target === "lyrics") {
      showToast(loginCopy("Casting lyric magic...", "歌词魔法施展中..."));
      randomizeCreationForLyricsRefresh(title);
    }
    const payload = await runLyricsGenerate(target === "style" ? "style_refresh" : "music_video");
    const raw = getApiData(payload);
    if (!payload?.ok || payload?.empty || !raw) {
      showToast(t("toast.seedRefreshFailed"));
      return;
    }
    const normalized = normalizeSongSeed(raw);
    if (target === "style") {
      if (styleInput && normalized.musicStyle) styleInput.value = normalized.musicStyle;
      state.songSeed = { ...(state.songSeed || {}), ...normalized };
      updateEnginePanels(titleInput?.value?.trim() || state.title, (lyricsInput?.value || "").split("\n"));
      renderSongSeedPreview(state.songSeed);
      showToast(t("toast.musicStyleRegenerated"));
      return;
    }
    if (target === "structure") {
      if (musicStructureInput) {
        musicStructureInput.value = [normalized.musicStructure, renderSectionBeatsText(normalized.sectionBeats)]
          .filter(Boolean)
          .join("\n\n");
      }
      state.songSeed = { ...(state.songSeed || {}), ...normalized };
      renderSongSeedPreview(state.songSeed);
      showToast(loginCopy("Music structure updated.", "音乐结构已更新。"));
      return;
    }
    if (target === "outline") {
      if (videoOutlineInput) videoOutlineInput.value = normalized.videoOutline;
      state.songSeed = { ...(state.songSeed || {}), ...normalized };
      renderSongSeedPreview(state.songSeed);
      showToast(loginCopy("Video outline updated.", "总视频提纲已更新。"));
      return;
    }
    if (target === "scenes") {
      if (sectionPromptsInput) sectionPromptsInput.value = renderSectionPromptsText(normalized.sectionPrompts);
      state.songSeed = { ...(state.songSeed || {}), ...normalized };
      renderSongSeedPreview(state.songSeed);
      showToast(loginCopy("Section prompts updated.", "分节视频脚本已更新。"));
      return;
    }
    applySongSeedToSettings(raw);
    if (target === "lyrics") {
      const universeSummary = describeSongSeedUniverse(state.songSeed);
      showToast(
        loginCopy(
          `Lyrics regenerated · ${[universeSummary, describeCreationRandomization()].filter(Boolean).join(" · ")}`,
          `歌词已刷新 · ${[universeSummary, describeCreationRandomization()].filter(Boolean).join(" · ")}`
        )
      );
      return;
    }
    showToast(t("toast.lyricsRegenerated"));
  } catch (_err) {
    showToast(t("toast.seedRefreshFailed"));
  } finally {
    setButtonBusy(trigger, false);
  }
}

function getApiData(payload) {
  if (!payload || typeof payload !== "object") return {};
  return payload.data && typeof payload.data === "object" ? payload.data : payload;
}

function getCurrentWorksOwnerKey() {
  const email = String(authState.user?.email || "").trim().toLowerCase();
  return email || "guest";
}

function readLocalWorks() {
  try {
    const raw = localStorage.getItem(LOCAL_WORKS_KEY);
    const parsed = raw ? JSON.parse(raw) : [];
    return Array.isArray(parsed) ? parsed : [];
  } catch (_err) {
    return [];
  }
}

function writeLocalWorks(works) {
  try {
    localStorage.setItem(LOCAL_WORKS_KEY, JSON.stringify(Array.isArray(works) ? works : []));
  } catch (_err) {
    // ignore storage quota
  }
}

function listLocalWorksForCurrentUser() {
  const ownerKey = getCurrentWorksOwnerKey();
  return readLocalWorks().filter((item) => String(item?.ownerKey || "") === ownerKey);
}

function upsertLocalWorkRecord(work) {
  const ownerKey = getCurrentWorksOwnerKey();
  const works = readLocalWorks();
  const workId = String(work?.local_id || work?.work_id || `local_${Date.now()}`);
  const next = {
    local_id: workId,
    work_id: work?.work_id ? String(work.work_id) : undefined,
    ownerKey,
    title: String(work?.title || "").trim() || "CSS MV",
    style: String(work?.style || "").trim(),
    work_type: normalizeWorkTypeClient(work?.work_type),
    cover_image: String(work?.cover_image || "").trim(),
    status: String(work?.status || "draft"),
    created_at: work?.created_at || new Date().toISOString(),
    lyrics_preview: String(work?.lyrics_preview || "").trim().slice(0, 500)
  };
  const index = works.findIndex(
    (item) =>
      String(item?.ownerKey || "") === ownerKey &&
      String(item?.local_id || item?.work_id || "") === workId
  );
  if (index >= 0) {
    works[index] = { ...works[index], ...next };
  } else {
    works.unshift(next);
  }
  writeLocalWorks(works.slice(0, 40));
  return next;
}

function workCreatedTimestamp(work) {
  const value = Date.parse(String(work?.created_at || ""));
  return Number.isFinite(value) ? value : 0;
}

function sortWorksNewestFirst(works) {
  return [...(Array.isArray(works) ? works : [])].sort((a, b) => {
    const timeDelta = workCreatedTimestamp(b) - workCreatedTimestamp(a);
    if (timeDelta !== 0) return timeDelta;
    return String(b?.title || "").localeCompare(String(a?.title || ""));
  });
}

