    item: item.target,
    action: item.action,
    priority: index === 0 ? "P1" : "P2",
    note:
      item.note ||
      checklistRows[index]?.note ||
      signoffEvidenceWallet?.summary ||
      dashboardCopy("No evidence collection note yet.", "当前还没有证据采集备注。")
