function buildWatchArchiveRegionLinkConclusionCard(probeSummary) {
  const payload = probeSummary && typeof probeSummary === "object" ? probeSummary : null;
  const conclusion = payload?.conclusion || {};
  const targets = Array.isArray(payload?.targets) ? payload.targets : [];
  const targetByName = Object.fromEntries(targets.map((item) => [String(item?.target || ""), item]));
  const localPublic = targetByName.local_public || null;
  const apiVmPublic = targetByName.api_vm_public || null;
  const gzvmPublic = targetByName.gzvm_public || null;
  const gzvmLoopback = targetByName.gzvm_loopback || null;

  const verdict = String(conclusion?.verdict || "");
  let headline = dashboardCopy("Probe summary unavailable", "探针摘要暂不可用");
  if (verdict === "server_recovered") {
    headline = dashboardCopy("Server recovered", "服务器已恢复");
  } else if (verdict === "cross_border_path_anomaly") {
    headline = dashboardCopy("Cross-border path anomaly", "跨境链路异常");
  } else if (verdict === "server_side_degradation") {
    headline = dashboardCopy("Server-side degradation", "服务器侧退化");
  } else if (verdict === "mixed_or_unknown") {
    headline = dashboardCopy("Mixed path health", "链路状态混合");
  }

  return {
    headline,
    verdict: verdict || "unknown",
    summary:
      conclusion?.summary ||
      dashboardCopy("No region link conclusion summary yet.", "当前还没有地区链路结论摘要。"),
    note: dashboardCopy(
      `Local=${localPublic?.http_success_rate ?? 0}% · api-vm=${apiVmPublic?.http_success_rate ?? 0}% · gzvm=${gzvmPublic?.http_success_rate ?? 0}% · loopback=${gzvmLoopback?.http_success_rate ?? 0}%`,
      `本机=${localPublic?.http_success_rate ?? 0}% · 美国机=${apiVmPublic?.http_success_rate ?? 0}% · 中国公网=${gzvmPublic?.http_success_rate ?? 0}% · 中国回环=${gzvmLoopback?.http_success_rate ?? 0}%`
    ),
    capturedAt: payload?.captured_at || ""
  };
}

function buildWatchArchiveRegionLinkTrendStrip(probeSummary) {
  const payload = probeSummary && typeof probeSummary === "object" ? probeSummary : null;
  const targets = Array.isArray(payload?.targets) ? payload.targets : [];
  return targets
    .filter((item) => item && item.target)
    .map((item) => ({
      target: String(item.target),
      httpRate: Number(item.http_success_rate || 0),
      tlsRate: Number(item.tls_success_rate || 0),
      resetRate: Number(item.reset_rate || 0)
    }));
}

function buildWatchArchiveCrossBorderAnomalyAlert(probeSummary) {
  const payload = probeSummary && typeof probeSummary === "object" ? probeSummary : null;
  const conclusion = payload?.conclusion || {};
  const verdict = String(conclusion?.verdict || "");
  const severe = verdict === "cross_border_path_anomaly";
  return {
    level: severe ? dashboardCopy("alert", "告警") : dashboardCopy("normal", "正常"),
    title: severe
      ? dashboardCopy("Cross-border path anomaly detected", "检测到跨境链路异常")
      : dashboardCopy("No cross-border anomaly detected", "当前未检测到跨境异常"),
    summary:
      conclusion?.summary ||
      dashboardCopy("No cross-border anomaly summary yet.", "当前还没有跨境异常摘要。"),
    note: severe
      ? dashboardCopy(
          "gzvm path is healthy, but non-gzvm public paths are still failing. This looks more like a network-path issue than a server crash.",
          "gzvm 路径健康，但非 gzvm 的公网路径仍在失败，更像链路问题，不像服务器宕机。"
        )
      : dashboardCopy(
          "Current probe set does not show a strong cross-border anomaly signal.",
          "当前探针集没有显示明显的跨境异常信号。"
        )
  };
}

function buildWatchSnapshotDiff(a, b) {
  if (!a || !b) return null;
  const aJournal = Array.isArray(a?.payload?.watch_outcome_journal) ? a.payload.watch_outcome_journal.length : 0;
  const bJournal = Array.isArray(b?.payload?.watch_outcome_journal) ? b.payload.watch_outcome_journal.length : 0;
  const aRollback = Array.isArray(a?.payload?.rollback_decision_audit_trail)
    ? a.payload.rollback_decision_audit_trail.length
    : 0;
  const bRollback = Array.isArray(b?.payload?.rollback_decision_audit_trail)
    ? b.payload.rollback_decision_audit_trail.length
    : 0;
  const aFlags = Array.isArray(a?.payload?.compliance_flags) ? a.payload.compliance_flags.length : 0;
  const bFlags = Array.isArray(b?.payload?.compliance_flags) ? b.payload.compliance_flags.length : 0;
  return {
    schema: "cssmv.watch_snapshot_diff.v1",
    from_snapshot: a.version_name,
    to_snapshot: b.version_name,
    journal_delta: bJournal - aJournal,
    rollback_decision_delta: bRollback - aRollback,
    compliance_flag_delta: bFlags - aFlags
  };
}

function isPanelVisible(panel) {
  return !!panel && !panel.classList.contains("hidden");
}

function persistMusicDeliveryDashboardRunId(runId) {
  try {
    if (runId) {
      localStorage.setItem(DELIVERY_DASHBOARD_RUN_ID_KEY, runId);
    } else {
      localStorage.removeItem(DELIVERY_DASHBOARD_RUN_ID_KEY);
    }
  } catch {}
}

function restoreMusicDeliveryDashboardRunId() {
  try {
    const cached = localStorage.getItem(DELIVERY_DASHBOARD_RUN_ID_KEY) || "";
    if (cached) {
      deliveryDashboardState.runId = cached;
    }
  } catch {}
  if (deliveryDashboardRunId) {
    deliveryDashboardRunId.value = deliveryDashboardState.runId || "";
  }
}

function extractRunId(value) {
  if (!value || typeof value !== "object") return "";
  return String(
    value.run_id ||
      value.runId ||
      value?.data?.run_id ||
      value?.data?.runId ||
      value?.run?.run_id ||
      value?.run?.runId ||
      ""
  ).trim();
}

function musicDeliveryPreviewKey(item) {
  return `${String(item?.category || "")}:${String(item?.relative_path || "")}`;
}

function musicDeliveryMixerKey(items) {
  return Array.isArray(items)
    ? items
        .map((item) => String(item?.relative_path || ""))
        .sort()
        .join("|")
    : "";
}

function musicDeliveryArrangementKey(item) {
  return item ? String(item.relative_path || item.download_url || "") : "";
}

function findMusicDeliveryArrangementItem(items, pattern) {
  return (Array.isArray(items) ? items : []).find((item) =>
    String(item?.relative_path || "").includes(pattern)
  ) || null;
}

function latestAppliedRewritePromotion() {
  const promotions = Array.isArray(deliveryDashboardState.response?.rewrite_promotions)
    ? deliveryDashboardState.response.rewrite_promotions
    : [];
  return promotions.find((entry) => entry?.apply_back_result?.status === "applied_back") || null;
}

function revisionFilesMatchArrangement(cueItem, phraseItem, promotion) {
  const revisions = Array.isArray(promotion?.apply_back_result?.revision_files)
    ? promotion.apply_back_result.revision_files
    : [];
  const cueRevision = String(revisions[0] || "").split("/").pop() || "";
  const phraseRevision = String(revisions[1] || "").split("/").pop() || "";
  const cuePath = String(cueItem?.relative_path || "");
  const phrasePath = String(phraseItem?.relative_path || "");
  return (!!cueRevision && cuePath.includes(cueRevision)) || (!!phraseRevision && phrasePath.includes(phraseRevision));
}

function stopMusicDeliveryMixerPlayback() {
  if (deliveryDashboardState.mixerLoopTimer) {
    clearTimeout(deliveryDashboardState.mixerLoopTimer);
    deliveryDashboardState.mixerLoopTimer = 0;
  }
  const nodes = Array.isArray(deliveryDashboardState.mixerNodes)
    ? deliveryDashboardState.mixerNodes
    : [];
  nodes.forEach((entry) => {
    try {
      entry?.source?.stop();
    } catch {}
    try {
      entry?.source?.disconnect();
    } catch {}
    try {
      entry?.gain?.disconnect();
    } catch {}
  });
  deliveryDashboardState.mixerNodes = [];
  deliveryDashboardState.mixerPlaying = false;
  deliveryDashboardState.mixerStartedAt = 0;
  deliveryDashboardState.mixerPlaybackWindow = null;
}

async function closeMusicDeliveryMixerContext() {
  stopMusicDeliveryMixerPlayback();
  const ctx = deliveryDashboardState.mixerContext;
  deliveryDashboardState.mixerContext = null;
  deliveryDashboardState.mixerMasterGain = null;
  if (ctx && typeof ctx.close === "function") {
    try {
      await ctx.close();
    } catch {}
  }
}

